// Normalize Wf47 callable receipt — same contract as external_receipt; does not use Set Wg test scenario.
const receipt = $input.first().json;
const base = { test_only: true, scenario: 'callable_wf47' };
const invalid = () => [{
  json: {
    ...base,
    inspect_status: 'blocked',
    decision_id: null,
    selected_option: null,
    update_id: null,
    inbound_text: 'missing-or-invalid-callable-receipt',
    response_kind: 'malformed',
    note_present: false,
    block_reason: 'missing_or_invalid_callable_receipt',
    test_only: true
  }
}];
if (!receipt || typeof receipt !== 'object' || receipt.test_only !== true) return invalid();
const has = (k) => Object.prototype.hasOwnProperty.call(receipt, k);
if (!has('inspect_status') || !has('decision_id') || !has('selected_option') || !has('update_id')) return invalid();
let response_kind = 'malformed';
if (receipt.note_present === true && receipt.decision_id) response_kind = 'note';
else if (receipt.decision_id && ['1', '2', '3'].includes(String(receipt.selected_option))) response_kind = 'option';
const inbound_text = receipt.inbound_text || (receipt.decision_id && receipt.selected_option
  ? 'dp:' + receipt.decision_id + ':' + receipt.selected_option
  : 'missing-or-invalid-callable-receipt');
return [{
  json: {
    ...base,
    inspect_status: receipt.inspect_status,
    decision_id: receipt.decision_id,
    selected_option: receipt.selected_option,
    update_id: receipt.update_id,
    inbound_text,
    response_kind,
    note_present: !!receipt.note_present,
    note_preview_sanitized: receipt.note_preview_sanitized || receipt.note_preview || null,
    block_reason: receipt.block_reason || null,
    duplicate_or_stale: !!receipt.duplicate_or_stale,
    allowed_chat_configured: receipt.allowed_chat_configured,
    offset_after_placeholder: receipt.offset_after_placeholder ?? null,
    last_handled_update_id: receipt.last_handled_update_id ?? null,
    external_receipt_source: 'wf47_callable'
  }
}];

// Build sanitized inbound (fixtures or Wf47 external receipt). No Telegram API.
const setRow = $('Set Wg test scenario').first().json;
const scenario = String(setRow.scenario || 'valid_close').trim();
const base = { test_only: true, scenario };
const invalidExternal = () => [{
  json: {
    ...base,
    inspect_status: 'blocked',
    decision_id: null,
    selected_option: null,
    update_id: null,
    inbound_text: 'missing-or-invalid-external-receipt',
    response_kind: 'malformed',
    note_present: false,
    block_reason: 'missing_or_invalid_external_receipt',
    test_only: true
  }
}];
if (scenario === 'external_receipt') {
  const raw = setRow.manual_receipt_json;
  if (raw === undefined || raw === null || String(raw).trim() === '' || String(raw).trim() === '{}') {
    return invalidExternal();
  }
  let receipt;
  try {
    receipt = typeof raw === 'string' ? JSON.parse(String(raw).trim()) : raw;
  } catch (e) {
    return invalidExternal();
  }
  if (!receipt || typeof receipt !== 'object' || receipt.test_only !== true) {
    return invalidExternal();
  }
  const has = (k) => Object.prototype.hasOwnProperty.call(receipt, k);
  if (!has('inspect_status') || !has('decision_id') || !has('selected_option') || !has('update_id')) {
    return invalidExternal();
  }
  let response_kind = 'malformed';
  if (receipt.note_present === true && receipt.decision_id) {
    response_kind = 'note';
  } else if (receipt.decision_id && ['1', '2', '3'].includes(String(receipt.selected_option))) {
    response_kind = 'option';
  }
  const inbound_text = receipt.inbound_text || (receipt.decision_id && receipt.selected_option
    ? 'dp:' + receipt.decision_id + ':' + receipt.selected_option
    : 'missing-or-invalid-external-receipt');
  return [{
    json: {
      ...base,
      inspect_status: receipt.inspect_status,
      decision_id: receipt.decision_id,
      selected_option: receipt.selected_option,
      update_id: receipt.update_id,
      inbound_text,
      response_kind,
      note_present: !!receipt.note_present,
      note_preview_sanitized: receipt.note_preview_sanitized || receipt.note_preview || null,
      block_reason: receipt.block_reason || null,
      duplicate_or_stale: !!receipt.duplicate_or_stale,
      allowed_chat_configured: receipt.allowed_chat_configured,
      offset_after_placeholder: receipt.offset_after_placeholder ?? null,
      last_handled_update_id: receipt.last_handled_update_id ?? null,
      external_receipt_source: 'wf47'
    }
  }];
}
const fixtures = {
  valid_close: {
    inspect_status: 'accepted',
    decision_id: 'D-9998-T',
    selected_option: '1',
    update_id: 986228900,
    inbound_text: 'dp:D-9998-T:1',
    response_kind: 'option',
    note_present: false
  },
  duplicate: {
    inspect_status: 'accepted',
    decision_id: 'D-9998-T',
    selected_option: '1',
    update_id: 986228900,
    inbound_text: 'dp:D-9998-T:1',
    response_kind: 'option',
    note_present: false
  },
  unknown: {
    inspect_status: 'accepted',
    decision_id: 'D-9999-X',
    selected_option: '2',
    update_id: 986228901,
    inbound_text: 'dp:D-9999-X:2',
    response_kind: 'option',
    note_present: false
  },
  stale_closed: {
    inspect_status: 'accepted',
    decision_id: 'D-9998-T',
    selected_option: '2',
    update_id: 986228902,
    inbound_text: 'dp:D-9998-T:2',
    response_kind: 'option',
    note_present: false
  },
  note_only: {
    inspect_status: 'note_placeholder',
    decision_id: 'D-9998-T',
    selected_option: null,
    update_id: 986228903,
    inbound_text: 'note:D-9998-T:TEST_ONLY_follow_up',
    response_kind: 'note',
    note_present: true,
    note_preview_sanitized: 'TEST_ONLY_follow_up'
  },
  malformed: {
    inspect_status: 'blocked',
    decision_id: null,
    selected_option: null,
    update_id: null,
    inbound_text: 'not-a-valid-dp-response',
    response_kind: 'malformed',
    note_present: false
  }
};
const f = fixtures[scenario] || fixtures.malformed;
return [{ json: { ...base, ...f } }];

// Correlate inbound to wg_decision_state_test. No raw Telegram identifiers.
const callableRows = $('Normalize Wf47 callable receipt').all();
const manualRows = $('Build sanitized inbound test input').all();
const inb = (callableRows.length ? callableRows[0].json : manualRows[0].json);
const rows = $('Data Table - Load wg decision state').all().map((i) => i.json);
const findRow = (id) => rows.find((r) => r && String(r.decision_id) === String(id));
let correlation_status = 'blocked';
let block_reason = 'malformed_response';
let decision_id = inb.decision_id || null;
let selected_option = inb.selected_option || null;
let update_id = inb.update_id ?? null;
let note_present = !!inb.note_present;
let persist_row = null;
const now = new Date().toISOString();
if (inb.response_kind === 'malformed' || !decision_id) {
  block_reason = 'malformed_response';
} else if (inb.response_kind === 'note') {
  const row = findRow(decision_id);
  if (!row) {
    block_reason = 'unknown_decision_id';
  } else {
    correlation_status = 'note_recorded';
    block_reason = null;
    const preview = String(inb.note_preview_sanitized || inb.inbound_text || '').slice(0, 80);
    persist_row = {
      decision_id,
      status: String(row.status || 'open'),
      selected_option: row.selected_option || '',
      created_at: row.created_at || now,
      closed_at: row.closed_at || '',
      update_id: String(update_id || row.update_id || ''),
      note_preview: preview,
      source: 'TEST ONLY'
    };
  }
} else if (inb.response_kind === 'option') {
  const row = findRow(decision_id);
  if (!row) {
    block_reason = 'unknown_decision_id';
  } else if (String(row.status) === 'closed') {
    if (update_id != null && String(row.update_id) === String(update_id)) {
      block_reason = 'duplicate_or_already_closed';
    } else {
      block_reason = 'already_closed_or_stale';
    }
  } else if (String(row.status) === 'open' && ['1', '2', '3'].includes(String(selected_option))) {
    correlation_status = 'closed';
    block_reason = null;
    persist_row = {
      decision_id,
      status: 'closed',
      selected_option: String(selected_option),
      created_at: row.created_at || now,
      closed_at: now,
      update_id: String(update_id),
      note_preview: row.note_preview || '',
      source: 'TEST ONLY'
    };
  } else {
    block_reason = 'malformed_response';
  }
}
return {
  json: {
    correlation_status,
    block_reason,
    decision_id,
    selected_option,
    update_id,
    note_present,
    prior_status: decision_id ? (findRow(decision_id)?.status || 'missing') : 'missing',
    persist_row,
    test_only: true
  }
};

const c = $('Correlate inbound to decision state').item.json;
const p = c.persist_row;
return { json: p };

const c = $('Correlate inbound to decision state').item.json;
return {
  json: {
    correlation_status: c.correlation_status,
    decision_id: c.decision_id,
    selected_option: c.selected_option,
    update_id: c.update_id,
    note_present: c.note_present,
    block_reason: c.block_reason,
    prior_status: c.prior_status,
    state_persisted: c.persist_row !== null && c.persist_row !== undefined,
    test_only: true
  }
};

const d = $input.item.json;
return {
  json: {
    inspect_status: d.correlation_status,
    decision_id: d.decision_id || null,
    selected_option: d.selected_option || null,
    update_id: d.update_id ?? null,
    note_present: d.note_present || false,
    block_reason: d.block_reason || null,
    prior_status: d.prior_status || null,
    state_persisted: d.state_persisted === true,
    test_only: true
  }
};
